212: func (c *Controller) updateCRDSpec(crd *apiextensionsv1.CustomResourceDefinition, name, versionName string, v3 *spec3.OpenAPI) error {
213: 	gv := schema.GroupVersion{
214: 		Group:   crd.Spec.Group,
215: 		Version: versionName,
216: 	}
217: 
218: 	_, ok := c.specsByGVandName[gv]
219: 	reason := "update"
220: 	if !ok {
221: 		reason = "add"
222: 		c.specsByGVandName[gv] = map[string]*spec3.OpenAPI{}
223: 	}
224: 
225: 	oldSpec, ok := c.specsByGVandName[gv][name]
226: 	if ok {
227: 		if reflect.DeepEqual(oldSpec, v3) {
228: 			// no changes to CRD
229: 			return nil
230: 		}
231: 	}
232: 	c.specsByGVandName[gv][name] = v3
233: 	regenerationCounter.With(map[string]string{"crd": name, "group": gv.Group, "version": gv.Version, "reason": reason})
234: 	return c.updateGroupVersion(gv)
235: }
