23: // ToKubeOpenAPI converts a structural schema to go-openapi schema. It is faithful and roundtrippable.
24: func (s *Structural) ToKubeOpenAPI() *spec.Schema {
25: 	if s == nil {
26: 		return nil
27: 	}
28: 
29: 	ret := &spec.Schema{}
30: 
31: 	if s.Items != nil {
32: 		ret.Items = &spec.SchemaOrArray{Schema: s.Items.ToKubeOpenAPI()}
33: 	}
34: 	if s.Properties != nil {
35: 		ret.Properties = make(map[string]spec.Schema, len(s.Properties))
36: 		for k, v := range s.Properties {
37: 			ret.Properties[k] = *v.ToKubeOpenAPI()
38: 		}
39: 	}
40: 	if s.AdditionalProperties != nil {
41: 		ret.AdditionalProperties = &spec.SchemaOrBool{
42: 			Allows: s.AdditionalProperties.Bool,
43: 			Schema: s.AdditionalProperties.Structural.ToKubeOpenAPI(),
44: 		}
45: 	}
46: 	s.Generic.toKubeOpenAPI(ret)
47: 	s.Extensions.toKubeOpenAPI(ret)
48: 	s.ValueValidation.toKubeOpenAPI(ret)
49: 	s.ValidationExtensions.toKubeOpenAPI(ret)
50: 	return ret
51: }
